// Helper function to dynamically rewrite relative paths of header, logo, and footer links
window.updateNavigationLinks = function() {
  try {
    var path = location.pathname;
    // Remove empty segments and any segments ending in .html
    var segments = path.split("/").filter(function(s) {
      return s && s.indexOf(".html") === -1;
    });
    
    var rootIndex = segments.indexOf("captura");
    var depth = 0;
    if (rootIndex !== -1) {
      depth = segments.length - 1 - rootIndex;
    } else {
      depth = segments.length;
    }
    if (depth < 0) depth = 0;
    
    var prefix = "";
    for (var i = 0; i < depth; i++) {
      prefix += "../";
    }
    
    var menuLinks = {
      "home": "index.html",
      "about": "about/index.html",
      "prizes": "prizes/index.html",
      "schedule": "schedule/index.html",
      "jury": "jury/index.html",
      "registration": "registration/index.html",
      "gallery": "gallery/index.html",
      "contact": "contact/index.html"
    };
    
    // Update header nav links
    document.querySelectorAll(".l-header__list a").forEach(function(link) {
      var parentLi = link.closest(".l-header__list");
      if (parentLi) {
        var pageName = parentLi.getAttribute("data-page-name");
        if (pageName && menuLinks[pageName]) {
          link.setAttribute("href", prefix + menuLinks[pageName]);
        }
      }
    });
    
    // Update header logo
    var logoLink = document.querySelector(".l-header__logo");
    if (logoLink) {
      logoLink.setAttribute("href", prefix + "index.html");
    }
    
    // Update drawer menu links
    document.querySelectorAll(".l-menu-body__link").forEach(function(link) {
      var text = link.textContent.trim().toLowerCase();
      if (text.indexOf("home") !== -1) link.setAttribute("href", prefix + "index.html");
      else if (text.indexOf("about") !== -1) link.setAttribute("href", prefix + "about/index.html");
      else if (text.indexOf("prizes") !== -1) link.setAttribute("href", prefix + "prizes/index.html");
      else if (text.indexOf("schedule") !== -1) link.setAttribute("href", prefix + "schedule/index.html");
      else if (text.indexOf("jury") !== -1) link.setAttribute("href", prefix + "jury/index.html");
      else if (text.indexOf("registration") !== -1) link.setAttribute("href", prefix + "registration/index.html");
      else if (text.indexOf("gallery") !== -1) link.setAttribute("href", prefix + "gallery/index.html");
      else if (text.indexOf("contact") !== -1) link.setAttribute("href", prefix + "contact/index.html");
    });
    
    // Update footer logo
    document.querySelectorAll(".l-footer__logo a").forEach(function(link) {
      link.setAttribute("href", prefix + "index.html");
    });
    
    // Update footer nav links
    document.querySelectorAll(".l-footer__nav-list a").forEach(function(link) {
      var text = link.textContent.trim().toLowerCase();
      if (text.indexOf("home") !== -1) link.setAttribute("href", prefix + "index.html");
      else if (text.indexOf("about") !== -1) link.setAttribute("href", prefix + "about/index.html");
      else if (text.indexOf("prizes") !== -1) link.setAttribute("href", prefix + "prizes/index.html");
      else if (text.indexOf("schedule") !== -1) link.setAttribute("href", prefix + "schedule/index.html");
      else if (text.indexOf("jury") !== -1) link.setAttribute("href", prefix + "jury/index.html");
      else if (text.indexOf("registration") !== -1) link.setAttribute("href", prefix + "registration/index.html");
      else if (text.indexOf("gallery") !== -1) link.setAttribute("href", prefix + "gallery/index.html");
      else if (text.indexOf("contact") !== -1) link.setAttribute("href", prefix + "contact/index.html");
    });
  } catch (e) {
    console.error("Error updating navigation links dynamically:", e);
  }
};

// Global Performance Optimizations for ScrollTrigger
(function() {
  function initOptimizations() {
    if (window.ScrollTrigger) {
      ScrollTrigger.config({
        limitCallbacks: true,
        ignoreMobileResize: true
      });
      // Optionally normalize scroll on touch devices to prevent lag
      if ('ontouchstart' in window || navigator.maxTouchPoints > 0) {
        // ScrollTrigger.normalizeScroll(true);
      }
      console.log("GSAP ScrollTrigger configured with performance optimizations.");
    } else {
      setTimeout(initOptimizations, 100);
    }
  }
  initOptimizations();
})();
